PyTypeObject* DoInitWrapperBorder(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperBorderType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperBorderPyMethodDefs;
	PyType->tp_getset = FUPyWrapperBorderGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperBorder(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(UBorder::StaticClass(), DoInitWrapperBorder);
}

FUPyWrapperBorder* UPyIsBorder(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperBorderType))
	{
		return (FUPyWrapperBorder*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, UBorder*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperBorder* PyBorder = UPyIsBorder(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PyBorder))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyBorder->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'UBorder'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
